INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('83019b17-7ca8-5707-ae92-254092e08ad3', 'ac13fde8-c53f-49dd-bdca-618241eb7414', 'He is tall ___ handsome.', '他很高且很帥。', 'and', 'but', 'or', 'so', '連接詞，用於連接兩個對等的形容詞。', 'and 連接兩個優點。'),
('3870f2d6-a35b-5edb-b482-fe58591e2327', '0d503313-f24a-4195-8140-6fd95a400606', 'Look at that cat. ___ is sleeping on the sofa.', '看那隻貓。___正在沙發上睡覺。', 'it', 'he', 'she', 'we', '代名詞：用來指代非人類的單數對象。', '指代貓咪（單數）時，通常用 it。'),
('7601d870-f79d-5d93-b742-764b0316e4d7', '670e26fd-407b-4388-8514-bd71291e9652', '___ ocean is very deep.', '海洋非常深。', 'the', 'a', 'an', 'some', '定冠詞，用於指代特定的事物。', '指特定的事物時，前面要用 the。'),
('eb720bb0-8514-5905-9d01-11b0e4c536cb', '08d7bf36-48f0-4253-a22b-7357bfa6e2a1', 'The end ___ the movie was very sad.', '這部電影的結局非常悲傷。', 'of', 'in', 'for', 'at', '介係詞，用來表示所屬關係', 'A ___ B 結構常表示「B 的 A」'),
('813a056e-2af2-570b-837f-2ca48396505f', 'c71bd206-4042-406c-8bc2-46572ad87585', 'She is going ___ Japan for a holiday.', '她要去日本度假。', 'to', 'from', 'in', 'on', '表示方向、目的地或對象的介系詞。', 'to → 向 (前往某處)'),
('1f507680-349f-50eb-853b-4a72f8d597fb', '863f960c-9dea-4632-a9cb-3487b5c50eab', 'They ___ my classmates.', '他們是我的同學。', 'are', 'like', 'help', 'meet', 'be 動詞，用於複數主詞表示「是」。', 'They / We / You → are'),
('d0f05018-6ae2-5e21-b275-5a383f95048f', '689e8620-8af8-45d0-b3cc-53eb54374dfc', '___ is my favorite book.', '這是我最喜歡的一本書。', 'This', 'It', 'Someone', 'Anything', 'This 在此為代名詞，用來指代近處的事物。', 'This (這) → 手指著近處的東西說。');
